const body = $('Webhook').item.json.body;
const dbResult = $input.item.json;

// Input validation
const sessionId = (body.session_id || '').replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 100) || `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
let userMessage = (body.message || '').slice(0, 500).trim();
if (!userMessage) throw new Error('Empty message');

// Load existing history or start fresh
let history = [];
if (dbResult && dbResult.messages_json) {
  try {
    history = JSON.parse(dbResult.messages_json);
  } catch(e) {
    history = [];
  }
}

// Keep only last 10 messages to stay within context limits
if (history.length > 10) {
  history = history.slice(-10);
}

return {
  session_id: sessionId,
  user_message: userMessage,
  history: history
};

const geminiResponse = $input.item.json;
const context = $('Prepare Context').item.json;

// Extract reply from Gemini response
let reply = 'Entschuldigung, ich konnte Ihre Anfrage gerade nicht verarbeiten. Bitte versuchen Sie es erneut oder schreiben Sie uns direkt an anfragen@freyaivisions.de';

try {
  reply = geminiResponse.candidates[0].content.parts[0].text;
} catch(e) {
  console.error('Gemini parse error:', e);
}

// Build updated history
const updatedHistory = [
  ...context.history,
  { role: 'user', content: context.user_message },
  { role: 'model', content: reply }
];

// Keep only last 20 messages total
const trimmedHistory = updatedHistory.slice(-20);

return {
  session_id: context.session_id,
  reply: reply,
  messages_json: JSON.stringify(trimmedHistory),
  user_message: context.user_message
};
